import{_ as t,o as a,c as i,a2 as d}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"API d’image aléatoire et galerie publique","description":"","frontmatter":{},"headers":[],"relativePath":"fr-FR/Other/random-image-api-and-public-gallery.md","filePath":"fr-FR/Other/random-image-api-and-public-gallery.md","lastUpdated":1781962217000}'),r={name:"fr-FR/Other/random-image-api-and-public-gallery.md"};function s(o,e,n,l,c,p){return a(),i("div",null,[...e[0]||(e[0]=[d(`<h1 id="api-d-image-aleatoire-et-galerie-publique" tabindex="-1">API d’image aléatoire et galerie publique <a class="header-anchor" href="#api-d-image-aleatoire-et-galerie-publique" aria-label="Permalink to &quot;API d’image aléatoire et galerie publique&quot;">​</a></h1><p>Ces deux fonctions se configurent ici :</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Paramètres système -&gt; Autres paramètres</span></span></code></pre></div><h2 id="api-d-image-aleatoire" tabindex="-1">API d’image aléatoire <a class="header-anchor" href="#api-d-image-aleatoire" aria-label="Permalink to &quot;API d’image aléatoire&quot;">​</a></h2><p>L’API d’image aléatoire choisit au hasard un fichier dans les dossiers configurés. Elle peut servir à afficher un fond de site, faire tourner des avatars ou appeler des images aléatoires depuis une page externe.</p><p>Une fois activée, utilisez :</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://votre-domaine/random</span></span></code></pre></div><h2 id="parametres-de-l-api" tabindex="-1">Paramètres de l’API <a class="header-anchor" href="#parametres-de-l-api" aria-label="Permalink to &quot;Paramètres de l’API&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Description</th></tr></thead><tbody><tr><td>Activer</td><td>Active ou désactive <code>/random</code>; désactivée, la route refuse l’accès</td></tr><tr><td>Dossiers</td><td>Limite les dossiers dans lesquels les fichiers peuvent être choisis</td></tr><tr><td>Exemple d’appel</td><td>Génère un lien d’API prêt à copier</td></tr></tbody></table><p>Vous pouvez sélectionner plusieurs dossiers. Si vous autorisez seulement <code>/landscape/</code> et <code>/portrait/</code>, l’API ne choisira que des fichiers dans ces dossiers ou leurs sous-dossiers.</p><h2 id="parametres-principaux" tabindex="-1">Paramètres principaux <a class="header-anchor" href="#parametres-principaux" aria-label="Permalink to &quot;Paramètres principaux&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Paramètre</th><th>Exemple</th><th>Description</th></tr></thead><tbody><tr><td><code>dir</code></td><td><code>/landscape/</code></td><td>Dossier cible</td></tr><tr><td><code>content</code></td><td><code>image</code></td><td>Type de média : <code>image</code>, <code>video</code>, <code>audio</code>, ou une combinaison</td></tr><tr><td><code>orientation</code></td><td><code>auto</code></td><td><code>portrait</code>, <code>landscape</code> ou <code>auto</code></td></tr><tr><td><code>type</code></td><td><code>url</code></td><td>Vide redirige ; <code>url</code> renvoie du texte ; <code>json</code> renvoie du JSON</td></tr><tr><td><code>origin</code></td><td><code>1</code></td><td>Avec <code>type=url</code>, renvoie un lien complet</td></tr><tr><td><code>age</code></td><td><code>all-ages,r12</code></td><td>Filtre par classification d’âge</td></tr><tr><td><code>tag</code></td><td><code>wallpaper,sky</code></td><td>Ne garde que les fichiers avec ces tags</td></tr><tr><td><code>ex</code></td><td><code>private</code></td><td>Exclut les fichiers avec ces tags</td></tr></tbody></table><h2 id="formats-de-reponse" tabindex="-1">Formats de réponse <a class="header-anchor" href="#formats-de-reponse" aria-label="Permalink to &quot;Formats de réponse&quot;">​</a></h2><p>Sans <code>type</code>, l’API redirige directement vers le fichier aléatoire.</p><p><code>type=url</code> renvoie un lien en texte brut.</p><p><code>type=json</code> renvoie les informations du fichier : lien, ID, nom, type, tags, classification et autres données.</p><h2 id="restrictions-d-acces" tabindex="-1">Restrictions d’accès <a class="header-anchor" href="#restrictions-d-acces" aria-label="Permalink to &quot;Restrictions d’accès&quot;">​</a></h2><p>L’API respecte les règles publiques définies dans le panneau.</p><table tabindex="0"><thead><tr><th>Règle</th><th>Effet</th></tr></thead><tbody><tr><td>Limite de dossiers</td><td>Ne choisit que dans les dossiers autorisés</td></tr><tr><td>Liste noire</td><td>Les fichiers bloqués ne sont pas candidats</td></tr><tr><td>Mode liste blanche</td><td>Renvoie uniquement les fichiers explicitement autorisés</td></tr><tr><td>Classification d’âge</td><td>Filtre R12, R16, R18 selon le mode d’accès</td></tr></tbody></table><p>Si aucun fichier ne correspond, l’API indique qu’il n’y a pas de résultat.</p><h2 id="galerie-publique" tabindex="-1">Galerie publique <a class="header-anchor" href="#galerie-publique" aria-label="Permalink to &quot;Galerie publique&quot;">​</a></h2><p>La galerie publique fournit une page en lecture seule permettant aux visiteurs de parcourir les dossiers que vous rendez publics.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://votre-domaine/browse/nom-du-dossier</span></span></code></pre></div><h2 id="parametres-de-la-galerie" tabindex="-1">Paramètres de la galerie <a class="header-anchor" href="#parametres-de-la-galerie" aria-label="Permalink to &quot;Paramètres de la galerie&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Description</th></tr></thead><tbody><tr><td>Activer</td><td>Active ou désactive la galerie publique</td></tr><tr><td>Mode de chargement</td><td>Utilise le fichier original ou une miniature</td></tr><tr><td>Dossiers publics</td><td>Définit les dossiers accessibles aux visiteurs</td></tr></tbody></table><p>Exemple :</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/,/2/,/landscape/,/portrait/</span></span></code></pre></div><p>Avec cette configuration, les visiteurs peuvent ouvrir :</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://votre-domaine/browse/1</span></span>
<span class="line"><span>https://votre-domaine/browse/2</span></span>
<span class="line"><span>https://votre-domaine/browse/landscape</span></span>
<span class="line"><span>https://votre-domaine/browse/portrait</span></span></code></pre></div><p>Les dossiers non publiés sont refusés.</p><h2 id="fonctions-de-la-galerie" tabindex="-1">Fonctions de la galerie <a class="header-anchor" href="#fonctions-de-la-galerie" aria-label="Permalink to &quot;Fonctions de la galerie&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Fonction</th><th>Description</th></tr></thead><tbody><tr><td>Parcourir les dossiers</td><td>Voir les fichiers et sous-dossiers publiés</td></tr><tr><td>Rechercher</td><td>Chercher par nom, ID de fichier ou tag</td></tr><tr><td>Filtrer par type</td><td>Image, vidéo, audio ou autres fichiers</td></tr><tr><td>Filtrer par tag</td><td>Inclure ou exclure des tags</td></tr><tr><td>Filtrer par orientation</td><td>Paysage, portrait ou autres critères</td></tr><tr><td>Copier un lien</td><td>Copier le lien public du fichier</td></tr><tr><td>Prévisualiser</td><td>Voir images, vidéos et audio dans la page</td></tr></tbody></table>`,32)])])}const b=t(r,[["render",s]]);export{h as __pageData,b as default};
